package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.IOException;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;
    private File mockFile;
    private Charset charset;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
        mockFile = mock(File.class);
        charset = Charset.defaultCharset();
    }

    @Test
    void testPrintCreatesCSVPrinter() throws IOException {
        // Spy CSVFormat to stub print(File, Charset) method
        CSVFormat spyFormat = spy(csvFormat);

        CSVPrinter mockPrinter = mock(CSVPrinter.class);

        // Stub spyFormat.print(File, Charset) to return the mockPrinter
        doReturn(mockPrinter).when(spyFormat).print(any(File.class), any(Charset.class));

        // Now call the method under test
        CSVPrinter printer = spyFormat.print(mockFile, charset);

        assertNotNull(printer);
        assertSame(mockPrinter, printer);
    }

    @Test
    void testPrintThrowsIOException() {
        // We simulate that passing null charset throws NullPointerException as per current implementation
        assertThrows(NullPointerException.class, () -> csvFormat.print(mockFile, null));
    }
}
